noncompliant:
// Noncompliant - all branches do the same thing
if (condition1) {
    doSomething();
} else if (condition2) {
    doSomething();
} else {
    doSomething();
}

// Noncompliant - ternary with same values
int result = (x > 0) ? 42 : 42;

// Noncompliant - switch with identical implementations
switch (value) {
    case 1:
        process();
        break;
    case 2:
        process();
        break;
    default:
        process();
        break;
}

compliant:
// Compliant - different implementations
if (condition1) {
    doFirstThing();
} else if (condition2) {
    doSecondThing();
} else {
    doDefaultThing();
}

// Compliant - remove unnecessary conditional
doSomething();

// Compliant - meaningful different values
int result = (x > 0) ? x * 2 : 0;

// Compliant - different implementations
switch (value) {
    case 1:
        processTypeOne();
        break;
    case 2:
        processTypeTwo();
        break;
    default:
        processDefault();
        break;
}
